--
-- Table structure for table `contact_vehicles`
--

DROP TABLE IF EXISTS `contact_vehicles`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `contact_vehicles` (
  `id` int NOT NULL AUTO_INCREMENT,
  `contact_id` int DEFAULT NULL,
  `chassis_number` varchar(100) NOT NULL,
  `engine_number` varchar(100) NOT NULL,
  `model_id` int DEFAULT NULL,
  `variant_id` int DEFAULT NULL,
  `vehicle_make` varchar(100) DEFAULT NULL,
  `vehicle_model` varchar(100) DEFAULT NULL,
  `color` varchar(50) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0',
  `deleted_at` datetime DEFAULT NULL,
  `deleted_by` int DEFAULT NULL,
  `purchase_id` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_chassis` (`chassis_number`),
  UNIQUE KEY `uniq_engine` (`engine_number`),
  KEY `idx_vehicle_contact` (`contact_id`),
  KEY `fk_contact_vehicle_model` (`model_id`),
  KEY `fk_contact_vehicle_variant` (`variant_id`),
  KEY `idx_cv_chassis` (`chassis_number`),
  KEY `idx_cv_engine` (`engine_number`),
  KEY `idx_contact_vehicles_is_deleted` (`is_deleted`),
  KEY `idx_purchase_id` (`purchase_id`),
  CONSTRAINT `fk_contact_vehicle_model` FOREIGN KEY (`model_id`) REFERENCES `vehicle_models` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_contact_vehicle_variant` FOREIGN KEY (`variant_id`) REFERENCES `vehicle_variants` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_contact_vehicles_contact` FOREIGN KEY (`contact_id`) REFERENCES `contacts` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=693 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `contact_vehicles`
--

LOCK TABLES `contact_vehicles` WRITE;
