/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `trg_contact_vehicles_snapshot_au` AFTER UPDATE ON `contact_vehicles` FOR EACH ROW BEGIN
  BEGIN
    DECLARE done INT DEFAULT 0;
    DECLARE v_sale_id INT;

    DECLARE cur CURSOR FOR
      SELECT sale_id FROM sale_vehicle_links WHERE vehicle_id = NEW.id;

    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;

    OPEN cur;
    read_loop: LOOP
      FETCH cur INTO v_sale_id;
      IF done = 1 THEN
        LEAVE read_loop;
      END IF;
      CALL rebuild_sale_register_snapshot(v_sale_id);
    END LOOP;
    CLOSE cur;
  END;
END */;;
