CREATE TABLE `sales` (
  `id` int NOT NULL AUTO_INCREMENT,
  `customer_name` varchar(200) NOT NULL,
  `father_name` varchar(100) DEFAULT NULL,
  `age` int DEFAULT NULL,
  `mobile_number` varchar(20) DEFAULT NULL,
